17	func (l *List) Add(title string) {
18		l.items = append(l.items, Item{ID: len(l.items) + 1, Title: title})
19	}
20	
21	func (l *List) Complete(id int) {
22		for i, item := range l.items {
23			if item.ID == id {
24				l.items[i].Completed = true
25			}
26		}
27	}
28	
29	func (l *List) Filter(completed bool) []Item {
30		var result []Item
31		for _, item := range l.items {
32			if item.Completed != completed {
33				result = append(result, item)
34			}
35		}
36		return result
37	}
